#include <iostream>
#include <string>
#include <sstream>
#include <vector>

// Assuming the user's solution's main function is renamed to 'user_main'
// and takes no arguments, interacting via global std::cin/std::cout.
extern int user_main();

std::string run_test_case(const std::string& input) {
    std::stringstream ss_in(input);
    std::stringstream ss_out;

    // Redirect cin and cout
    std::streambuf* old_cin_buf = std::cin.rdbuf();
    std::streambuf* old_cout_buf = std::cout.rdbuf();
    std::cin.rdbuf(ss_in.rdbuf());
    std::cout.rdbuf(ss_out.rdbuf());

    // Call the user's main function
    user_main();

    // Restore cin and cout
    std::cin.rdbuf(old_cin_buf);
    std::cout.rdbuf(old_cout_buf);

    // Trim trailing newline from output for consistent comparison
    std::string output = ss_out.str();
    if (!output.empty() && output.back() == '\n') {
        output.pop_back();
    }
    return output;
}
